code = """import json
import ast
import re
from datetime import datetime

# Load variables from storage
businesss_path = var_call_jqdHgr0tAooat9z81Ywpb1Xr
ratings = var_call_siXlnmO8s1kfCSNj7TrUirym

# Read full business JSON file
with open(businesss_path, 'r') as f:
    businesses = json.load(f)

# Build avg rating dict
avg_by_id = {r['gmap_id']: float(r['avg_rating']) for r in ratings}

weekdays = set(['Monday','Tuesday','Wednesday','Thursday','Friday'])

# time parsing
time_re = re.compile(r"(?i)^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$")
sep_re = re.compile(r'[\u2013\u2014-]+')

def parse_time_token(tok):
    tok = tok.strip().upper().replace('.', '')
    m = time_re.match(tok)
    if not m:
        return None
    hour = int(m.group(1))
    minute = int(m.group(2)) if m.group(2) else 0
    ampm = m.group(3)
    if ampm == 'AM':
        if hour == 12:
            hour = 0
    else: # PM
        if hour != 12:
            hour += 12
    return hour*60 + minute

results = []

for b in businesses:
    gmap_id = b.get('gmap_id')
    hours_raw = b.get('hours')
    name = b.get('name')
    if not hours_raw or hours_raw in ('None', 'NONE', None):
        continue
    # hours_raw is string representation of list
    try:
        hours_list = ast.literal_eval(hours_raw)
    except Exception:
        # try to salvage by replacing unicode quotes
        try:
            hours_list = json.loads(hours_raw)
        except Exception:
            continue
    open_after_6 = False
    for day_entry in hours_list:
        if not isinstance(day_entry, (list, tuple)) or len(day_entry) < 2:
            continue
        day = day_entry[0]
        timestr = day_entry[1]
        if day not in weekdays:
            continue
        if not timestr or timestr.strip().lower() == 'closed':
            continue
        # split range
        parts = sep_re.split(timestr)
        if len(parts) < 2:
            continue
        end_token = parts[-1].strip()
        # Some entries may include multiple ranges separated by comma, take last
        if ',' in end_token:
            end_token = end_token.split(',')[-1].strip()
        # Ensure AM/PM present in end_token; if not, try to infer from start
        if not re.search(r'(?i)(AM|PM)', end_token):
            # try to append AM/PM from start token
            start_token = parts[0].strip()
            m = re.search(r'(?i)(AM|PM)', start_token)
            if m:
                end_token = end_token + m.group(1)
        end_minutes = parse_time_token(end_token)
        if end_minutes is None:
            continue
        if end_minutes > 18*60:
            open_after_6 = True
            break
    if not open_after_6:
        continue
    if gmap_id not in avg_by_id:
        continue
    results.append({'name': name, 'gmap_id': gmap_id, 'hours': hours_raw, 'avg_rating': avg_by_id[gmap_id]})

# sort by avg_rating desc
results_sorted = sorted(results, key=lambda x: x['avg_rating'], reverse=True)
top5 = results_sorted[:5]

print("__RESULT__:")
print(json.dumps(top5))"""

